INSERT INTO public.photos VALUES (23113, 'Vista a‚Ēú¬ģrea 2004', 'Vista a‚Ēú¬ģrea de Zaragoza en 2004, centrada en la plaza del Pilar. Fuente: www.facebook.com/photo.php?fbid=1777983065797482&set=...', 2004, 2004, 2004, 'Siglo XXI', 'CASCO HIST‚Ēú√īRICO', 41.65657400, -0.87932600, '0101000020E61000004AB890477023ECBFB3B3E89D0AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30738105011.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30738105011.webp', 'https://www.flickr.com/photos/zaragozaantigua/30738105011/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23168, 'Plaza del Pilar 2000', 'Ilustraci‚Ēú‚Ēān que acompa‚Ēú‚Ėía un texto firmado en 1979 por Alfonso Sol‚Ēú√≠ns Serrano, concejal de Tr‚Ēú√≠fico y Polic‚Ēú¬°a Municipal del Ayuntamiento de Zaragoza. Vemos el subsuelo de la plaza del Pilar, surcado por varias unidades de metro, en un ejercicio de prospectiva que sit‚Ēú‚ēĎa este escenario en el a‚Ēú‚Ėío 2000. El horadamiento, m‚Ēú√≠s modesto, se llev‚Ēú‚Ēā a cabo en 1991 para la construcci‚Ēú‚Ēān de un aparcamiento subterr‚Ēú√≠neo. Fuente: "Tr‚Ēú√≠fico y transporte en la Zaragoza 2000". Ayuntamiento de Zaragoza, 1979.', 2000, 2000, 2000, 'Siglo XXI', 'CASCO HIST‚Ēú√īRICO', 41.65642600, -0.87893100, '0101000020E610000033198EE73320ECBF3F1F65C405D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32950518995.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32950518995.webp', 'https://www.flickr.com/photos/zaragozaantigua/32950518995/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23279, 'C‚Ēú¬ģsar Augusto al preg‚Ēú‚Ēān 1961', 'Ayuntamiento de Zaragoza. Gerardo Sancho Ramo. 1961. Podr‚Ēú¬°a pasar por uno de los varios traslados de la estatua de C‚Ēú¬ģsar Augusto por la ciudad, pero no. Se trata de una de las carrozas participantes en el preg‚Ēú‚Ēān de las fiestas mayores de la ciudad, rodando por la calle Alfonso I, a punto de llegar a la Plaza del Pilar. Intenta ser una carroza romana, pero si el auriga es el hombre de hojalata, pues no.', 1961, 1961, 1961, 'Anos 60', 'CASCO HIST‚Ēú√īRICO', 41.65597700, -0.87920600, '0101000020E6100000A14D0E9F7422ECBFCFF6E80DF7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14817567187.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14817567187.webp', 'https://www.flickr.com/photos/zaragozaantigua/14817567187/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23288, 'Calle de Alfonso I 1958', 'Octubre de 1958. Calle de Alfonso I de Zaragoza. Al fondo, la confluencia con la plaza del Pilar. En el centro, imagen de la Virgen con las flores de la primera ofrenda realizada. Fuente: Colecci‚Ēú‚Ēān Jos‚Ēú¬ģ Vicente Moreno.', 1958, 1958, 1958, 'Anos 50', 'CASCO HIST‚Ēú√īRICO', 41.65595200, -0.87917500, '0101000020E6100000E0BE0E9C3322ECBF76DF313CF6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15810476761.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15810476761.webp', 'https://www.flickr.com/photos/zaragozaantigua/15810476761/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23300, 'Calle de Alfonso I 1967', 'La reina de las fiestas del Pilar de 1967 lleva en sus manos la Cruz de Lorena del sanatorio antituberculoso Royo Villanova, para depositarla ante la imagen de la Virgen del Pilar en la ofrenda de flores (antituberculosa). A la derecha, la Librer‚Ēú¬°a Arag‚Ēú‚Ēān, que hac‚Ēú¬°a esquina en la calle de Alfonso I con la plaza del Pilar. Fuente: Agencia EFE', 1967, 1967, 1967, 'Anos 60', 'CASCO HIST‚Ēú√īRICO', 41.65612700, -0.87916400, '0101000020E6100000E5417A8A1C22ECBFE48233F8FBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23988655753.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23988655753.webp', 'https://www.flickr.com/photos/zaragozaantigua/23988655753/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23312, 'Calle de Alfonso I c.1976', 'Imagen tomada en el ‚Ēú‚ēĎltimo tramo de la calle de Alfonso I y orientada hacia su principio desde el Coso Alto, al fondo. A la izquierda e inmediato, el esquinero comercio de los Almacenes de Mercer‚Ēú¬°a de Telesforo Garc‚Ēú¬°a de la Cruz, y el ingreso al Pasaje de la Industria y el Comercio, popularmente denominado El Cicl‚Ēú‚Ēān. A la derecha, la estimable fachada del establecimiento comercial de Urue‚Ēú‚Ėía (originalmente realizado en 1928 para Madurga y Compa‚Ēú‚Ėí‚Ēú¬°a). Hacia el fondo y a la derecha, los cruces que dan acceso al principio de la calle de Prudencio, en primer lugar, y a la de la Manifestaci‚Ēú‚Ēān, despu‚Ēú¬ģs. El escaso tr‚Ēú√≠nsito peatonal, y nulo rodado, sugieren que tal vez esta fotograf‚Ēú¬°a se realiz‚Ēú‚Ēā en un d‚Ēú¬°a no laborable. La se‚Ēú‚Ėíal de Circulaci‚Ēú‚Ēān prohibida, por si acaso. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'CASCO HIST‚Ēú√īRICO', 41.65607700, -0.87917400, '0101000020E6100000C9CA2F833122ECBF3354C554FAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45737794564.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45737794564.webp', 'https://www.flickr.com/photos/zaragozaantigua/45737794564/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23313, 'Plaza del Pilar 1962', 'Imagen capturada en la plaza del Pilar con la perspectiva de la calle de Alfonso I desde su arranque, al fondo, en el tramo alto del Coso, y centrada en un chaval haciendo pr‚Ēú√≠cticas de Guardia Urbano durante un cursillo de circulaci‚Ēú‚Ēān impartido por la OJE (Organizaci‚Ēú‚Ēān de Juventudes Espa‚Ēú‚Ėíolas). Tras el soleado muchacho y el Renault Dauphine Gordini que se encamina hacia la calle de Don Jaime I, chafl‚Ēú√≠n del inmueble del n‚Ē¨‚ēĎ 8 de la plaza del Pilar, ocupado en los bajos por la librer‚Ēú¬°a y tienda de material escolar Arag‚Ēú‚Ēān. La OJE hab‚Ēú¬°a sido creada en 1960 como refundaci‚Ēú‚Ēān de dos organizaciones juveniles, la antigua y obligatoria denominada "Frente de Juventudes", y la voluntaria "Falanges Juveniles de Franco", en una nueva organizaci‚Ēú‚Ēān de car‚Ēú√≠cter voluntario integrada en el Movimiento Nacional franquista.', 1962, 1962, 1962, 'Anos 60', 'CASCO HIST‚Ēú√īRICO', 41.65618400, -0.87919500, '0101000020E6100000A6D0798D5D22ECBF49145AD6FDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47968165051.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47968165051.webp', 'https://www.flickr.com/photos/zaragozaantigua/47968165051/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23790, 'Palacio de Ayerbe a‚Ēú‚Ėíos 30', 'A‚Ēú‚Ėíos 30 del siglo XX. Vista del palacio de los Marqueses de Ayerbe desde el Paseo del Ebro. Fue expropiado y derribado en 1942 para construir el nuevo Ayuntamiento. Las l‚Ēú√≠mparas de la mansi‚Ēú‚Ēān fueron donadas a la Bas‚Ēú¬°lica de El Pilar. A la izquierda, la Posada de los Reyes. Este palacio fue escenario, a finales del siglo XIX, de renombradas fiestas de sociedad, especialmente durante la visita de la Reina Mar‚Ēú¬°a Cristina en 1888. Fuente visual: Archivo Municipal, Archivo Mora.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST‚Ēú√īRICO', 41.65625600, -0.87718900, '0101000020E610000074266DAAEE11ECBFE2E6543200D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14710919438.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14710919438.webp', 'https://www.flickr.com/photos/zaragozaantigua/14710919438/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23791, 'Pl. del Pilar 1954', 'Jardines, autob‚Ēú‚ēĎs, caballo con carro.', 1954, 1954, 1954, 'Anos 50', 'CASCO HIST‚Ēú√īRICO', 41.65625900, -0.87884500, '0101000020E61000008F19A88C7F1FECBF535A7F4B00D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14725322669.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14725322669.webp', 'https://www.flickr.com/photos/zaragozaantigua/14725322669/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23792, 'Palacio de Ayerbe a‚Ēú‚Ėíos 30', 'A‚Ēú‚Ėíos 30 del siglo XX. En la calle del Pilar, puerta principal de acceso al palacio de los marqueses de Ayerbe, ocupado en sus ‚Ēú‚ēĎltimos a‚Ēú‚Ėíos por la congregaci‚Ēú‚Ēān de las religiosas Ang‚Ēú¬ģlicas de santa Genoveva. Estas monjas, hoy desplazadas a su Casa Generalicia de la plaza del Pilar 22, se dedican a gestionar hospeder‚Ēú¬°as. Fuente visual: Archivo Municipal, Archivo Mora.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST‚Ēú√īRICO', 41.65599500, -0.87756200, '0101000020E610000096CB46E7FC14ECBF75ABE7A4F7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14730512220.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14730512220.webp', 'https://www.flickr.com/photos/zaragozaantigua/14730512220/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23804, 'Copa del bal‚Ēú‚Ēān en el cesto 1984', 'Copa del Rey 1984. De 1933 es el primer Campeonato de Espa‚Ēú‚Ėía de Copa de baloncesto, que desde 1940 se disput‚Ēú‚Ēā como Copa de Su Excelencia el General‚Ēú¬°simo, y desde 1976 como Copa de Su Majestad el Rey. La edici‚Ēú‚Ēān de 1983-1984 se disput‚Ēú‚Ēā en Zaragoza, y la final fue disputada entre el CAI Zaragoza y el F.C. Barcelona. El resultado final (81-78) dio la victoria al equipo local por primera vez en su historia y fue un acontecimiento calificado, por ello, de hist‚Ēú‚Ēārico. En la imagen, momento estelar de la celebraci‚Ēú‚Ēān del t‚Ēú¬°tulo: los jugadores se encaminan hacia la Puerta Alta del Pilar, acompa‚Ēú‚Ėíados de gran n‚Ēú‚ēĎmero de seguidores, para escenificar la ofrenda simb‚Ēú‚Ēālica de la Copa a la Virgen. Al fondo, la arbolada plaza de La Seo, y a la derecha, la sede del Gobierno Civil, donde todav‚Ēú¬°a perduran s‚Ēú¬°mbolos del franquismo, aunque el PSOE gobernaba con mayor‚Ēú¬°a absoluta en todas las instituciones imaginables.', 1984, 1984, 1984, 'Anos 80', 'CASCO HIST‚Ēú√īRICO', 41.65632400, -0.87877500, '0101000020E6100000575BB1BFEC1EECBF3ACAC16C02D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15280746708.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15280746708.webp', 'https://www.flickr.com/photos/zaragozaantigua/15280746708/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23815, 'Pilar 1968', 'Imagen de la "Puerta Baja" del Pilar, o puerta principal por estar m‚Ēú√≠s cerca de la Virgen. A su derecha queda la "Torre Nueva" del Pilar, as‚Ēú¬° denominada cuando fue la torre de factura m‚Ēú√≠s joven, a comienzos del s.XX, t‚Ēú¬°tulo que le quitaron las dos de la ribera del Ebro, sesenteras ellas. En la imagen, el Pilar con abundante corriente de gente, y de aires, que de forma inusualmente rara la puerta del fondo est‚Ēú√≠ abierta, y deja ver la arboleda de Macanaz, en la margen izquierda. Fuente: "Zaragoza viva" (1969)', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST‚Ēú√īRICO', 41.65627200, -0.87803100, '0101000020E610000040F9BB77D418ECBFE8A38CB800D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15870381042.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15870381042.webp', 'https://www.flickr.com/photos/zaragozaantigua/15870381042/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23821, 'Palacio de Ayerbe c.1940', 'Entre las muchas historias e historietas que rodean al nunca bien ponderado palacio de los marqueses de Ayerbe de la calle del Pilar, destaca la que ata‚Ēú‚Ėíe a la cercana y antigua casa de Torrellas, en la que brillaba con luz propia su patio en tres alturas soportadas sobre seis columnas, todo un monumento g‚Ēú‚Ēātico-plateresco sin igual en la ciudad. Derribado en 1865 por la apertura de la calle Alfonso I, su entonces propietario, el Marqu‚Ēú¬ģs de Ayerbe, habr‚Ēú¬°a reciclado algunos de sus componentes para decorar su palacio de calle del Pilar. As‚Ēú¬°, por ejemplo, unas finas columnas de traza g‚Ēú‚Ēātica fueron adosadas como decoraci‚Ēú‚Ēān de la fachada, y con algunos arcos y capiteles del patio central se compuso un templete, cenador, o "quiosco". En la imagen, el quiosco reciclado de piezas del derribado palacio de Torrellas, instalado en los jardines del palacio de los Ayerbe. A su izquierda, el edificio denominado "Casas de los Infantes", junto al Callej‚Ēú‚Ēān del Retiro Bajo y el Pilar. Al fondo, la verja con vistas al paseo de la ribera y el Ebro. Cuando este otro palacio de Ayerbe tambi‚Ēú¬ģn caiga, para construir en su solar el actual edificio consistorial, el templete se ir‚Ēú√≠ con el resto de materiales de derribo, sin noticia de que hubiera sido nuevamente reciclado. Fuente visual: AHPZ. Juan Mora Insa.', 1940, 1940, 1940, 'Anos 40', 'CASCO HIST‚Ēú√īRICO', 41.65621500, -0.87731900, '0101000020E6100000001AA54BFF12ECBF841266DAFED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19148141195.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19148141195.webp', 'https://www.flickr.com/photos/zaragozaantigua/19148141195/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23831, 'NI‚Ēú‚Ėías de Garabandal 1965', 'El sacerdote zaragozano Luis Luna, en la plaza del Pilar, flanqueado por Loli y Jacinta, dos de las ni‚Ēú‚Ėías de San Sebasti‚Ēú√≠n de Garabandal (Cantabria) que protagonizaron en ese pueblo desde 1961 hasta 1965 variadas visiones de la Virgen del Carmen, el Sagrado Coraz‚Ēú‚Ēān de Jes‚Ēú‚ēĎs, los arc‚Ēú√≠ngeles san Miguel y san Gabriel y el ap‚Ēú‚Ēāstol Santiago, cabalgando el d‚Ēú¬°a de su fiesta. En el momento de la foto, estas apariciones ya hab‚Ēú¬°an concluido. El pueblo sigue siendo lugar de peregrinaci‚Ēú‚Ēān, aunque los fen‚Ēú‚Ēāmenos paranormales no obtuvieron la aprobaci‚Ēú‚Ēān oficial de la Iglesia. Se contabilizaron m‚Ēú√≠s de 2.300 ‚Ēú¬ģxtasis en 18 meses, lo que da un resultado de m‚Ēú√≠s de cuatro apariciones diarias. La Virgen profetiz‚Ēú‚Ēā el fin de los tiempos, pero parece algo confuso el momento concreto. Las apariciones marianas o mariofan‚Ēú¬°as son fen‚Ēú‚Ēāmenos de la religi‚Ēú‚Ēān cristiana, cuyo listado comienza con la del Pilar, precisamente. Suelen provocar resultados tur‚Ēú¬°sticos. Fuente visual: www.catholicrevelations.org/PR/the%20apparitions%20of%20g...', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST‚Ēú√īRICO', 41.65607000, -0.87830700, '0101000020E6100000C4211B48171BECBF80F10C1AFAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21950243813.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21950243813.webp', 'https://www.flickr.com/photos/zaragozaantigua/21950243813/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23835, 'Cabezudos 1967', 'Plaza del Pilar engalanada y con desfile de cabezudos de la comparsa de √Ē√á¬£Gigantes y Cabezudos√Ē√á√ė. Fuente visual: Foto Leonardo P‚Ēú¬ģrez Obis, donada por ‚Ēú√ľngel Hern‚Ēú√≠ndez Mostajo para www.rafaelcastillejo.com', 1967, 1967, 1967, 'Anos 60', 'CASCO HIST‚Ēú√īRICO', 41.65647100, -0.87876700, '0101000020E6100000A1BAB9F8DB1EECBFDFE2E13D07D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22753821277.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22753821277.webp', 'https://www.flickr.com/photos/zaragozaantigua/22753821277/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23837, 'Gigantes 1967', 'Plaza del Pilar engalanada y con desfile de gigantes de la comparsa de √Ē√á¬£Gigantes y Cabezudos√Ē√á√ė. Fuente visual: Foto Leonardo P‚Ēú¬ģrez Obis, donada por ‚Ēú√ľngel Hern‚Ēú√≠ndez Mostajo para www.rafaelcastillejo.com', 1967, 1967, 1967, 'Anos 60', 'CASCO HIST‚Ēú√īRICO', 41.65647100, -0.87876700, '0101000020E6100000A1BAB9F8DB1EECBFDFE2E13D07D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23148013535.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23148013535.webp', 'https://www.flickr.com/photos/zaragozaantigua/23148013535/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23838, 'Ofrenda de flores 1968', 'Plaza del Pilar durante la ofrenda de flores, a‚Ēú‚ēĎn sin la escultura-retablo de Pablo Serrano en el centro de la fachada, con representaci‚Ēú‚Ēān de la fabulosa venida de la Virgen del Pilar a la ciudad. Fuente visual: Foto Leonardo P‚Ēú¬ģrez Obis, donada por ‚Ēú√ľngel Hern‚Ēú√≠ndez Mostajo para www.rafaelcastillejo.com', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST‚Ēú√īRICO', 41.65647100, -0.87876700, '0101000020E6100000A1BAB9F8DB1EECBFDFE2E13D07D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23158017162.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23158017162.webp', 'https://www.flickr.com/photos/zaragozaantigua/23158017162/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23839, 'Plaza del Pilar 1965', 'Imagen tomada durante el legendario proceso de construcci‚Ēú‚Ēān de la nueva Casa Consistorial de la ciudad, ya en su tercera d‚Ēú¬ģcada de laboreo. La captura est‚Ēú√≠ centrada en el momento de colocaci‚Ēú‚Ēān del escudo de la ciudad, con su rampante le‚Ēú‚Ēān en piedra, en la fachada a la plaza del Pilar, justo encima de la puerta principal de ingreso, y debajo del espacio donde luego se colocar‚Ēú√≠ el reloj que mojonea los dominios de Cronos. Abajo, al nivel de los porches, ya se han instalado los pedestales sobre los que m‚Ēú√≠s tarde se colocar‚Ēú√≠n las estatuas de San Valero y del ‚Ēú√ľngel Custodio, obras de Pablo Serrano, flanqueando la entrada a la casa de todo el vecindario. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST‚Ēú√īRICO', 41.65601800, -0.87751000, '0101000020E6100000F836FDD98F14ECBF2ECBD765F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23338765971.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23338765971.webp', 'https://www.flickr.com/photos/zaragozaantigua/23338765971/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23840, 'Plaza del Pilar 1954', 'Imagen de los quioscos que flanqueaban el acceso a la bas‚Ēú¬°lica del Pilar desde la antigua plaza, en la zona de la "Puerta Baja" o principal del templo. Poco tiempo despu‚Ēú¬ģs, ‚Ēú√≠rboles y quioscos ser‚Ēú¬°an derribados y desmontados para despejar la visual y el espacio de la nueva plaza. Fuente visual: Gerardo Sancho Ramo, en AMZ.', 1954, 1954, 1954, 'Anos 50', 'CASCO HIST‚Ēú√īRICO', 41.65609800, -0.87841100, '0101000020E6100000024BAE62F11BECBF4A7CEE04FBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23566993224.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23566993224.webp', 'https://www.flickr.com/photos/zaragozaantigua/23566993224/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23843, 'Plaza del Pilar c.1940', 'Vista de la plaza del Pilar desde la torre de Santiago del templo. En la parte superior, parte del caser‚Ēú¬°o eliminado para ensanchar el espacio de la plaza. Fuente: www.facebook.com/photo.php?fbid=1043104609064066&set=...', 1940, 1940, 1940, 'Anos 40', 'CASCO HIST‚Ēú√īRICO', 41.65595000, -0.87818800, '0101000020E610000032AB77B81D1AECBFD5E76A2BF6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24392821002.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24392821002.webp', 'https://www.flickr.com/photos/zaragozaantigua/24392821002/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23848, 'Pl. del Pilar 1955', 'Un barrendero municipal desempe‚Ēú‚Ėía sus funciones en la plaza del Pilar con el fondo de la puerta sureste o Baja del templo. La imagen recoge otra de las singularidades de la nueva y gran plaza: la precoz instalaci‚Ēú‚Ēān en sus aleda‚Ēú‚Ėíos de una colonia de palomas que pronto se convirtieron en se‚Ēú‚Ėía de identidad de este di‚Ēú√≠fano espacio. Fuente visual: Foto: Joan Miquel i Quintilla, en barcelonafotoantic.com/', 1955, 1955, 1955, 'Anos 50', 'CASCO HIST‚Ēú√īRICO', 41.65609800, -0.87841100, '0101000020E6100000024BAE62F11BECBF4A7CEE04FBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24795569146.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24795569146.webp', 'https://www.flickr.com/photos/zaragozaantigua/24795569146/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23851, 'Plaza del Pilar 1955', 'Canicular imagen de la plaza del Pilar, humanizada al reciente gusto por los grandes espacios abiertos, bien despejados de edificios y vegetaci‚Ēú‚Ēān para favorecer as‚Ēú¬° una r‚Ēú√≠pida insolaci‚Ēú‚Ēān veraniega, y un pasmo atroz los d‚Ēú¬°as de insensato viento norte. La instalaci‚Ēú‚Ēān de macetillas, como forma de intentar paliar las cosas, es algo enternecedor. Por encima de la iglesia metropolitana de N‚Ē¨¬¨ S‚Ē¨¬¨ del Pilar, despunta la estructura de obra de la nueva torre noroeste, luego denominada de San Francisco de Borja, o "del ascensor". Un sacerdote apura el paso a la busca de resguardo. Esta joya visual fue realizada por el fot‚Ēú‚Ēāgrafo franc‚Ēú¬ģs Jean Paul Margnac en el verano de 1955, durante su paso por la pen‚Ēú¬°nsula Ib‚Ēú¬ģrica, desde Par‚Ēú¬°s, y con destino hacia tierras m‚Ēú√≠s meridionales. Fuente visual: www.flickr.com/photos/jean-paul-margnac/26699094216/in/al...', 1955, 1955, 1955, 'Anos 50', 'CASCO HIST‚Ēú√īRICO', 41.65609800, -0.87841100, '0101000020E6100000024BAE62F11BECBF4A7CEE04FBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27026490630.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27026490630.webp', 'https://www.flickr.com/photos/zaragozaantigua/27026490630/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23853, '&quot;Falla&quot; 1940', 'El programa de las "Fiestas de Primavera" del a‚Ēú‚Ėío 1940 incluy‚Ēú‚Ēā una luminosa innovaci‚Ēú‚Ēān: la importaci‚Ēú‚Ēān de la valenciana costumbre de prender fuego a iconos fungibles, denominada "Falla", un antiguo y pagano acto de renovaci‚Ēú‚Ēān y purificaci‚Ēú‚Ēān reconvertido, al adscribirlo al patr‚Ēú‚Ēān cat‚Ēú‚Ēālico de los carpinteros. Por ser la primera vez, la representaci‚Ēú‚Ēān que fue pasto de la pasi‚Ēú‚Ēān iconoclasta en la Zaragoza del momento no pod‚Ēú¬°a ser otra que la de la imagen: titulada "Aparici‚Ēú‚Ēān", en ella el planeta Tierra es sostenido por ‚Ēú√≠ngeles, mientras del ‚Ēú¬ģter desciende una columna que es posada por otros ‚Ēú√≠ngeles menores justo en la romana Caesaraugusta. De espaldas a la trascendente escena, ni m‚Ēú√≠s ni menos que la fant‚Ēú√≠stica llegada en carne mortal de la virgen del pilar a Zaragoza, los can‚Ēú‚Ēānicos cuatro ap‚Ēú‚Ēāstoles evangelistas, a lo suyo. Esta local "falla", a la espera de su holocausto, aparece estacionada en la antigua plaza del Pilar, todav‚Ēú¬°a arbolada. Al fondo, se abre la calle de Alfonso I. Fuente visual: Mar‚Ēú¬°n Chivite, revista "Arag‚Ēú‚Ēān".', 1940, 1940, 1940, 'Anos 40', 'CASCO HIST‚Ēú√īRICO', 41.65631400, -0.87901200, '0101000020E6100000655419C6DD20ECBF17F4DE1802D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27120945983.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27120945983.webp', 'https://www.flickr.com/photos/zaragozaantigua/27120945983/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23858, 'Juan de Lanuza 1591', '"La prisi‚Ēú‚Ēān de Lanuza", ‚Ēú‚Ēāleo sobre lienzo, Carlos Larraz y Micheto, 1858. Representaci‚Ēú‚Ēān del momento en el que Juan de Lanuza El Joven, Justicia de Arag‚Ēú‚Ēān (derecha), es apresado por orden de Felipe II. Aunque se dice que fue prendido en el palacio de la Diputaci‚Ēú‚Ēān del Reino, el escenario del cuadro es el palacio de Torrellas, en la plaza del Pilar, en cuyos s‚Ēú‚Ēātanos cuentan que fue encarcelado a la espera de su decapitaci‚Ēú‚Ēān. Fuente visual: www.museodelprado.es', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HIST‚Ēú√īRICO', 41.65597200, -0.87900200, '0101000020E610000081CB63CDC820ECBFBD8BF7E3F6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27661482829.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27661482829.webp', 'https://www.flickr.com/photos/zaragozaantigua/27661482829/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23865, 'La Pilara 1982', 'La Pilara en la ceremonia civil que el 10 de octubre de 1982 dio carta de naturaleza a la hom‚Ēú‚Ēānima cabezuda que desde entonces forma parte de la comparsa local, en una imagen capturada en el balc‚Ēú‚Ēān principal del Ayuntamiento y en la que Pilar Lahuerta Cajo posa entre el alcalde Ram‚Ēú‚Ēān Sainz de Varanda y La Pilara cabezuda. De esta forma se homenajeaba a esta veterana vedette de music-hall en el Sal‚Ēú‚Ēān Oasis de Zaragoza, primer cabaret de la ciudad que comenz‚Ēú‚Ēā siendo el Royal Concert. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1982, 1982, 1982, 'Anos 80', 'CASCO HIST‚Ēú√īRICO', 41.65601800, -0.87751000, '0101000020E6100000F836FDD98F14ECBF2ECBD765F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30183732101.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30183732101.webp', 'https://www.flickr.com/photos/zaragozaantigua/30183732101/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23866, 'Plaza del Pilar 1989', 'Tradicional ofrenda de flores realizada desde 1958 en el marco de las fiestas mayores en octubre, y que desde 1969 culminaba en la escultura de Pablo Serrano titulada Venida de la Virgen del Pilar, adosada a la bas‚Ēú¬°lica. En la imagen figuran, de izquierda a derecha, el delegado del Gobierno en Arag‚Ēú‚Ēān y gobernador Civil, Carlos P‚Ēú¬ģrez Anad‚Ēú‚Ēān; el alcalde, Antonio Gonz‚Ēú√≠lez Trivi‚Ēú‚Ėío; y el presidente de la Diputaci‚Ēú‚Ēān Provincial, Jos‚Ēú¬ģ Marco Berges. Estos dos ‚Ēú‚ēĎltimos portan la vara de mando con que fueron investidos. Fuente visual: Antonio Calvo Pedr‚Ēú‚Ēās, AMZ.', 1989, 1989, 1989, 'Anos 80', 'CASCO HIST‚Ēú√īRICO', 41.65647100, -0.87876700, '0101000020E6100000A1BAB9F8DB1EECBFDFE2E13D07D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30630443061.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30630443061.webp', 'https://www.flickr.com/photos/zaragozaantigua/30630443061/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23881, 'Pl. del Pilar 1903', 'Entramado junto a la puerta baja de la bas‚Ēú¬°lica, con escaleras de acceso a una r‚Ēú¬ģpl‚Ēú¬°ca de la Virgen del Pilar, durante la celebraci‚Ēú‚Ēān el 19 de marzo de 1903 de la inauguraci‚Ēú‚Ēān de las obras de la segunda torre del Pilar, que terminar‚Ēú√≠ de ser erigida en 1907 en ese punto del templo. Fuente visual: Foto Manuel Olivar', 1903, 1903, 1903, 'Anos 1900', 'CASCO HIST‚Ēú√īRICO', 41.65621300, -0.87814600, '0101000020E6100000779FE3A3C519ECBFE31A9FC9FED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31448215390.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31448215390.webp', 'https://www.flickr.com/photos/zaragozaantigua/31448215390/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23889, 'Bar‚Ēú‚Ēān Von Wichmann 1940', 'El bar‚Ēú‚Ēān Gerhard Von Wichmann, teniente coronel del ej‚Ēú¬ģrcito imperial del k‚Ēú√≠iser Guillermo, posa con una familiar en la boda de una de sus hijas en 1940, posiblemente en la puerta del Pilar. Este arist‚Ēú‚Ēācrata fue uno de los 347 "alemanes del Camer‚Ēú‚ēĎn" residentes en Zaragoza, desde que en 1916 los ej‚Ēú¬ģrcitos franc‚Ēú¬ģs y brit‚Ēú√≠nico conquistaron esa colonia germana. Tras pasar por la Guinea Espa‚Ēú‚Ėíola, llegaron a Espa‚Ēú‚Ėía, que les dio asilo. Von Wichmann se cas‚Ēú‚Ēā con una ejeana en 1921 y vivi‚Ēú‚Ēā en la calle de Ponciano Ponzano, donde eran c‚Ēú¬ģlebres sus fiestas. La "peque‚Ēú‚Ėía Alemania" tuvo una destacada influencia social y econ‚Ēú‚Ēāmica en la ciudad: Colegio Alem‚Ēú√≠n en la calle de Cervantes (con su secci‚Ēú‚Ēān de las Juventudes Hitlerianas en 1939), Casa de los Alemanes en Moncasi, foto Carlos Skogler en el Coso, Tinte de los Alemanes, salchichas Kurtz, cementerio alem‚Ēú√≠n, cervezas La Zaragozana (Hans Schneider), guantes Schoeman, m‚Ēú¬ģtodo de producci‚Ēú‚Ēān de la Azucarera, impulso del balompi‚Ēú¬ģ con el campo de la calle Bilbao... Fuente: "La herencia germana de Zaragoza", Sergio del Molino, Heraldo de Arag‚Ēú‚Ēān, 2007.', 1940, 1940, 1940, 'Anos 40', 'CASCO HIST‚Ēú√īRICO', 41.65630900, -0.87827500, '0101000020E6100000ED9E3C2CD41AECBF0589EDEE01D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32169099336.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32169099336.webp', 'https://www.flickr.com/photos/zaragozaantigua/32169099336/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23896, 'Ayuntamiento 1965', 'Imagen capturada en el interior del despacho del Sr. Alcalde en el nuevo edificio del ayuntamiento de Zaragoza. El maravilloso artesonado de la techumbre (comienzos del siglo XVI) pertenec‚Ēú¬°a originalmente a la derribada casa de los marqueses de Osera en la antigua calle Mayor, junto a la iglesia de Santa Cruz. El moderno mobiliario fue adquirido a la emblem‚Ēú√≠tica empresa Sim‚Ēú‚Ēān Loscertales Bona. Al fondo, el lienzo de Francisco Mar‚Ēú¬°n Bag‚Ēú‚ēĚ‚Ēú¬ģs titulado "Retrato del general Francisco Franco Bahamonde" (1939). Fuente visual : El Ayuntamiento de Zaragoza (1977).', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST‚Ēú√īRICO', 41.65601800, -0.87751000, '0101000020E6100000F836FDD98F14ECBF2ECBD765F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38307606071.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38307606071.webp', 'https://www.flickr.com/photos/zaragozaantigua/38307606071/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23898, 'Plaza del Pilar 1985', 'Imagen capturada en la plaza del Pilar durante el paso de un ciudadano con sus campaneros pantalones ante la fachada principal del Ayuntamiento. La escultura de San Valero, realizada por Pablo Serrano e instalada veinte a‚Ēú‚Ėíos antes en esa ubicaci‚Ēú‚Ēān, a la diestra del ingreso municipal, deviene en aparici‚Ēú‚Ēān siniestra por el capricho de las sombras de un atardecer canicular.', 1985, 1985, 1985, 'Anos 80', 'CASCO HIST‚Ēú√īRICO', 41.65601800, -0.87751000, '0101000020E6100000F836FDD98F14ECBF2ECBD765F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48773887311.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48773887311.webp', 'https://www.flickr.com/photos/zaragozaantigua/48773887311/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23911, 'Templo del Pilar 1940', 'In‚Ēú¬ģdita imagen capturada ante la puerta Baja del templo del Pilar, con un posado en el que la "Excelent‚Ēú¬°sima se‚Ēú‚Ėíora dona Carmen Polo, esposa de su excelencia el Jefe del Estado" y Ram‚Ēú‚Ēān Serrano Su‚Ēú‚Ėíer, "Excelent‚Ēú¬°simo Sr. Ministro de la Gobernaci‚Ēú‚Ēān", flanquean a los dos hijos de ‚Ēú¬ģste, "Pepito y Fernando Serrano Polo" disfrazados de Infantes del Pilar (hab‚Ēú¬°an sido nombrados Infantes de Honor), su madre, "do‚Ēú‚Ėía Zita Polo de Serrano". y su prima "Carmencita Polo de Franco". Esta foto fue tomada tras la ceremonia en la que Pepito y Fernando recibieron por vez primera "el Pan de los ‚Ēú√ľngeles" o "cuerpo de Cristo escondido bajo la apariencia de pan" en la Santa Capilla del Santo Templo Metropolitano del Pilar el d‚Ēú¬°a 30 de mayo (festividad de San Fernando III) del a‚Ēú‚Ėío 1940, coincidente con la solemne conmemoraci‚Ēú‚Ēān por el R‚Ēú¬ģgimen del XIX Centenario de "la venida de la Virgen del Pilar en carne mortal a Zaragoza". Se trat‚Ēú‚Ēā de una emotiva ceremonia oficiada por el se‚Ēú‚Ėíor can‚Ēú‚Ēānigo don Santiago Guallar y celebrada en la intimidad familiar, de la que todo el mundo fue informado con profusi‚Ēú‚Ēān de detalles por participar en ella notables personajes de la Espa‚Ēú‚Ėía de la ‚Ēú¬ģpoca.', 1940, 1940, 1940, 'Anos 40', 'CASCO HIST‚Ēú√īRICO', 41.65623200, -0.87826200, '0101000020E6100000C539EAE8B81AECBF5A4B0169FFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53219502995.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53219502995.webp', 'https://www.flickr.com/photos/zaragozaantigua/53219502995/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23914, 'Plaza del Pilar 1905', 'Comercial escena capturada en el marco de la plaza del Pilar y centrada en un coche de recogida de ropas de la empresa "La Higiene de Zaragoza", Lavadero modelo mec‚Ēú√≠nico de Anechina y Compa‚Ēú‚Ėí‚Ēú¬°a ubicado en el barrio de Ruise‚Ēú‚Ėíores, "primero y ‚Ēú‚ēĎnico en Espa‚Ēú‚Ėía de este sistema". Con una capacidad semanal de tratamiento de hasta 50.000 piezas, ofrec‚Ēú¬°a las mejores garant‚Ēú¬°as de higiene, perfecci‚Ēú‚Ēān, rapidez y econom‚Ēú¬°a a la hora de tratar la limpieza mec‚Ēú√≠nica de las diversas prendas de ropa, desde los pa‚Ēú‚Ėíuelos de bolsillo hasta las mantas grandes de lana. El buen desempe‚Ēú‚Ėío de sus funciones permiti‚Ēú‚Ēā a esta empresa abrir pronto varias sucursales en la calle del Cinco de Marzo, la plaza de San Felipe y la calle de Roda.', 1905, 1905, 1905, 'Anos 1900', 'CASCO HIST‚Ēú√īRICO', 41.65632000, -0.87877700, '0101000020E610000085436FF1F01EECBFF9DA334B02D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54330744919.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54330744919.webp', 'https://www.flickr.com/photos/zaragozaantigua/54330744919/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23915, 'Calle del Pilar 1942', 'Imagen capturada desde la altura de la calle de Juan Mart‚Ēú¬°n Goicoechea y centrada en el lado de los impares de la calle del Pilar, con detalle del proceso de derribo de la casa-palacio del marqu‚Ēú¬ģs de Ayerbe sito en el n‚Ēú‚ēĎmero 15 de ese vial. El despejado entorno de primer t‚Ēú¬ģrmino es resultado de la demolici‚Ēú‚Ēān integral previa de todos los edificios del lado de los pares de la calle del Pilar, as‚Ēú¬° como los de las manzanas delimitadas entre la plaza del Pilar y las calles de Latassa, Bayeu y Don Jaime I, todo como consecuencia de la prevista ejecuci‚Ēú‚Ēān de la uni‚Ēú‚Ēān de las plazas de La Seo y del Pilar. La casa-palacio de los Ayerbe fue derribada en el mes de mayo de ese a‚Ēú‚Ėío, y en este caso la acci‚Ēú‚Ēān fue realizada por operarios municipales "con el fin de recoger cuidadosamente los materiales art‚Ēú¬°sticos" que pudiera contener, algo que fue muy bien valorado en la prensa de la ‚Ēú¬ģpoca, sin ninguna otra consideraci‚Ēú‚Ēān que realizar ante el derribo de este referencial palacio zaragozano que, como en otros tantos casos, fuese y no hubo nada. A la izquierda del solar palaciego, vista parcial de las viviendas seriadas que llegaban hasta el callej‚Ēú‚Ēān del Retiro Bajo del Pilar, entre las que se encontraba la antigua posada del Pilar. A la derecha, inmuebles que llegaban hasta el callej‚Ēú‚Ēān que las separaba de la Lonja, entre las que se encontraba la ribere‚Ēú‚Ėía posada de los Reyes. Todas ellas fueron igualmente expropiadas y derribadas luego para conformar el espacio sobre el que, m‚Ēú√≠s tarde, emprender la construcci‚Ēú‚Ēān de la nueva Casa Consistorial.', 1942, 1942, 1942, 'Anos 40', 'CASCO HIST‚Ēú√īRICO', 41.65601800, -0.87751000, '0101000020E6100000F836FDD98F14ECBF2ECBD765F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54705272758.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54705272758.webp', 'https://www.flickr.com/photos/zaragozaantigua/54705272758/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24012, 'Plaza del Pilar 1975', 'Mayo es el mes de las flores, y en Zaragoza, adem‚Ēú√≠s, era el de las Fiestas de Primavera, de las Majas Internacionales, y de la cuestaci‚Ēú‚Ēān para subnormales. El holismo sist‚Ēú¬ģmico de la ciudad parece ilimitado, como el universo, y amable, como sus can‚Ēú‚Ēānigos. A la derecha, el Pilar. Al fondo, Goya nos mira de reojo. Fuente visual: Gerardo Sancho Ramo, Archivo P‚Ēú‚ēĎblico Municipal.', 1975, 1975, 1975, 'Anos 70', 'CASCO HIST‚Ēú√īRICO', 41.65660300, -0.87931200, '0101000020E61000000B5F5FEB5223ECBF4DBA2D910BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24171100959.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24171100959.webp', 'https://www.flickr.com/photos/zaragozaantigua/24171100959/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24051, 'Pl. del Pilar 1903', 'Foto: Manuel Olivar. Procesi‚Ēú‚Ēān de la Virgen en la plaza del Pilar, con la calle de Alfonso I al fondo a la derecha, en los actos de inauguraci‚Ēú‚Ēān de las obras de construcci‚Ēú‚Ēān de la segunda de las torres del templo, el 19 de marzo de 1903. Ser‚Ēú√≠ terminada en 1907. Fuente visual: Heraldo de Arag‚Ēú‚Ēān.', 1903, 1903, 1903, 'Anos 1900', 'CASCO HIST‚Ēú√īRICO', 41.65617300, -0.87839300, '0101000020E6100000682101A3CB1BECBF55C2137AFDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31448748770.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31448748770.webp', 'https://www.flickr.com/photos/zaragozaantigua/31448748770/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24084, 'Calle Alfonso 1916', 'Foto: S‚Ēú√≠nchez Rom‚Ēú√≠n. Salida de la calle de Alfonso I a la plaza del Pilar de la comitiva de la Cruz Roja postulante para los perjudicados por la tormenta que desbord‚Ēú‚Ēā los r‚Ēú¬°os de la comarca de Torrijo y Ateca a finales de julio de 1916, ocasionando numerosas muertes y da‚Ēú‚Ėíos. A la izquierda, mercer‚Ēú¬°a de Telesforo Garc‚Ēú¬°a, en el edificio del pasaje de la Industria y el Comercio. Fuente: Revista Blanco y Negro, 6-8-1916.', 1916, 1916, 1916, 'Anos 10', 'CASCO HIST‚Ēú√īRICO', 41.65607700, -0.87917400, '0101000020E6100000C9CA2F833122ECBF3354C554FAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42703534905.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42703534905.webp', 'https://www.flickr.com/photos/zaragozaantigua/42703534905/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24114, 'Plaza del Pilar 1908', 'Imagen capturada en la plaza del Pilar durante la visita del rey Alfonso XIII el d‚Ēú¬°a 14 de junio de ese a‚Ēú‚Ėío para asistir a diversos eventos relacionados con el primer centenario del asedio franc‚Ēú¬ģs de 1808. En este caso se trata de la llegada de la comitiva, tras su arribo a la estaci‚Ēú‚Ēān de Campo Sepulcro, al exterior del templo del Pilar para asistir a solemne misa y Te Deum cantado. Bajo un sol bochornoso, anuncio de tormenta, el coche de caballos aparece estacionado ante la Puerta Baja del templo, donde un grupo de s‚Ēú‚ēĎbditos aguardan expectantes al real visionado.', 1908, 1908, 1908, 'Anos 1900', 'CASCO HIST‚Ēú√īRICO', 41.65623200, -0.87826200, '0101000020E6100000C539EAE8B81AECBF5A4B0169FFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52081345377.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52081345377.webp', 'https://www.flickr.com/photos/zaragozaantigua/52081345377/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24223, 'Plaza del Pilar 1952', 'Con el pertinente permiso de la autoridad competente, el piloto-paracaidista ingl‚Ēú¬ģs James Will se lanz‚Ēú‚Ēā en paraca‚Ēú¬°das desde la casa del Marqu‚Ēú¬ģs de Ayerbe que alberga el pasaje de la Industria y el Comercio o El Cicl‚Ēú‚Ēān, el d‚Ēú¬°a grande de las fiestas del Pilar. A la derecha, calle de Alfonso I. Al fondo y a la izquierda, fachada en obras de la nueva Casa consistorial. Fuente visual: foto Miguel Mar‚Ēú¬°n Chivite.', 1952, 1952, 1952, 'Anos 50', 'CASCO HIST‚Ēú√īRICO', 41.65601400, -0.87905100, '0101000020E6100000DC8310902F21ECBFECDB4944F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15929882955.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15929882955.webp', 'https://www.flickr.com/photos/zaragozaantigua/15929882955/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24225, 'Ofrenda de flores 1958', 'Aunque ya en 1939, con motivo de la victoria del bando fascista en la Guerra Civil, se organiz‚Ēú‚Ēā en Zaragoza una manifestaci‚Ēú‚Ēān oficial con pase‚Ēú¬°llo de personas ataviadas con trajes regionales y provistas de flores para agradecer a la Virgen del Pilar la derrota del comunismo, no fue hasta 1958 cuando se regulariz‚Ēú‚Ēā el ritual como "ofrenda de flores", que se ven‚Ēú¬°a realizando sin mayor organizaci‚Ēú‚Ēān desde 1953. El acto, que ha tenido una participaci‚Ēú‚Ēān creciente, consiste en ataviar con manto floral una reproducci‚Ēú‚Ēān de la Virgen, tras desfilar por distintas calles de la ciudad. Est‚Ēú√≠ inspirado en ritos similares levantinos. El Ayuntamiento sufrag‚Ēú‚Ēā las flores hasta 1986. En 1998 se cambi‚Ēú‚Ēā su ubicaci‚Ēú‚Ēān para llevarlo a una pir‚Ēú√≠mide met‚Ēú√≠lica, a sugerencia del cineasta Bigas Luna. En la imagen, miembros de la Agrupaci‚Ēú‚Ēān Art‚Ēú¬°stica Aragonesa bailan la jota durante la primera ofrenda oficializada, en la que participaron unas 2.000 personas. Fuente: "Zaragoza y sus fiestas".', 1958, 1958, 1958, 'Anos 50', 'CASCO HIST‚Ēú√īRICO', 41.65640400, -0.87866500, '0101000020E61000009279E40F061EECBF577BD80B05D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19723056288.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19723056288.webp', 'https://www.flickr.com/photos/zaragozaantigua/19723056288/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24229, 'Plaza del Pilar 1953', 'Imagen capturada en el punto donde la calle de Alfonso I desemboca en la plaza del Pilar durante las hom‚Ēú‚Ēānimas fiestas de principios del mes de octubre, como ilustra la notable profusi‚Ēú‚Ēān de banderas y gallardetes con los colores de la bandera nacional. Al fondo, fachada del templo con el aspecto tras la intervenci‚Ēú‚Ēān que a mediados de la d‚Ēú¬ģcada anterior le confiri‚Ēú‚Ēā la gran galer‚Ēú¬°a decorativa de estatuas. La plaza todav‚Ēú¬°a presenta los ‚Ēú√≠rboles que caracterizaban este espacio, poco antes de ser arrancados.', 1953, 1953, 1953, 'Anos 50', 'CASCO HIST‚Ēú√īRICO', 41.65606400, -0.87929200, '0101000020E6100000444DF4F92823ECBF9E0AB8E7F9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23692412890.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23692412890.webp', 'https://www.flickr.com/photos/zaragozaantigua/23692412890/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24240, 'Ofrenda de Flores c.1962', 'Imagen capturada desde la altura del inmueble del n‚Ē¨‚ēĎ 40 de la calle de Alfonso I, chaflanero con la plaza del Pilar, y centrada en el pa‚Ēú‚Ėío central de la fachada principal del hom‚Ēú‚Ēānimo templo durante la ceremonia de la tradicional, desde 1958, Ofrenda de Flores. En el momento de realizar esta imagen, el Nuncio de Su Santidad (por ausencia del arzobispo Casimiro Morcillo Gonz‚Ēú√≠lez, desplazado a Roma por el Concilio Vaticano II), rodeado de autoridades militares, religiosas e institucionales, oficia una ceremonia junto a la carroza de plata realizada en 1933 por Jorge Albareda que soporta un icono mariano tambi‚Ēú¬ģn en plata realizado en el primer tercio del siglo XVII, y que de forma llamativa figura sin el ni‚Ēú‚Ėío en brazos, como era tradici‚Ēú‚Ēān en aquellos tiempos, coet‚Ēú√≠neos con el desaparecido templo mud‚Ēú¬ģjar de Santa Mar‚Ēú¬°a del Pilar.', 1962, 1962, 1962, 'Anos 60', 'CASCO HIST‚Ēú√īRICO', 41.65652900, -0.87874500, '0101000020E6100000ADC090D5AD1EECBF13F06B2409D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49317468018.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49317468018.webp', 'https://www.flickr.com/photos/zaragozaantigua/49317468018/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24863, 'Plaza del Pilar 1949', 'Carro de tracci‚Ēú‚Ēān asnal en la plaza del Pilar. A la izquierda, obras de construcci‚Ēú‚Ēān del Ayuntamiento. Al fondo, la Lonja y la Seo. Fuente: www.facebook.com/photo.php?fbid=10211232610224662&set...', 1949, 1949, 1949, 'Anos 40', 'CASCO HIST‚Ēú√īRICO', 41.65606100, -0.87808200, '0101000020E6100000C899266C3F19ECBF2D978DCEF9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33051351094.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33051351094.webp', 'https://www.flickr.com/photos/zaragozaantigua/33051351094/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24882, 'Manzana Casas Plaza del Pilar 1885', 'Fondo Documental Hist‚Ēú‚Ēārico de las Cortes de Arag‚Ēú‚Ēān. (1885). Nueva manzana de casas en la Plaza del Pilar, esquina a la calle de Alfonso I, propiedad del Sr. Marqu‚Ēú¬ģs de Ayerbe.', 1885, 1885, 1885, 'Siglo XIX', 'CASCO HIST‚Ēú√īRICO', 41.65598400, -0.87900200, '0101000020E610000081CB63CDC820ECBF8159A148F7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14877551375.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14877551375.webp', 'https://www.flickr.com/photos/zaragozaantigua/14877551375/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24912, 'Ayuntamiento 1955', 'Las obras del edificio del Ayuntamiento se prolongaron durante dos d‚Ēú¬ģcadas, de 1946 a 1965. En la foto, estado de la fachada a‚Ēú‚ēĎn con mucho por construir. Fuente: www.delcampe.net', 1955, 1955, 1955, 'Anos 50', 'CASCO HIST‚Ēú√īRICO', 41.65613500, -0.87759800, '0101000020E6100000C91EA1664815ECBF67614F3BFCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21648452989.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21648452989.webp', 'https://www.flickr.com/photos/zaragozaantigua/21648452989/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25054, 'Franco y se‚Ēú‚Ėíora 1961', 'Ayuntamiento de Zaragoza/Foto LOZANO. Setiembre 1961. El V Congreso Eucar‚Ēú¬°stico Nacional tuvo lugar en Zaragoza del 17 al 24 de setiembre de 1961. El Jefe del Estado y su se‚Ēú‚Ėíora acudieron a presidir la ceremonia de clausura. En la imagen, ambos dos seres en el espacio a ellos reservado en la ceremonia, que tuvo lugar en la Plaza del Pilar, donde se rindi‚Ēú‚Ēā homenaje a Jes‚Ēú‚ēĎs Sacramentado.', 1961, 1961, 1961, 'Anos 60', 'CASCO HIST‚Ēú√īRICO', 41.65640400, -0.87866500, '0101000020E61000009279E40F061EECBF577BD80B05D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14740980628.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14740980628.webp', 'https://www.flickr.com/photos/zaragozaantigua/14740980628/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25061, 'Borb‚Ēú‚Ēān y Borb‚Ēú‚Ēān 1970', '"1970 Zaragoza.- El Pr‚Ēú¬°ncipe Juan Carlos, acompa‚Ēú‚Ėíado del Infante Felipe ataviado con un traje de ma‚Ēú‚Ėío, saluda al p‚Ēú‚ēĎblico congregado que asiste a la tradicional ofrenda floral a la Virgen del Pilar con motivo de su festividad." Efe / Y.V.', 1970, 1970, 1970, 'Anos 70', 'CASCO HIST‚Ēú√īRICO', 41.65640400, -0.87866500, '0101000020E61000009279E40F061EECBF577BD80B05D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14934936241.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14934936241.webp', 'https://www.flickr.com/photos/zaragozaantigua/14934936241/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25075, 'Eva Per‚Ēú‚Ēān 1947', 'Foto: Luis Mompel. Mar‚Ēú¬°a Eva Duarte de Per‚Ēú‚Ēān, "Evita", fue una actriz y pol‚Ēú¬°tica argentina. En 1946 se convirti‚Ēú‚Ēā en primera dama, por estar casada con Juan Domingo Per‚Ēú‚Ēān, y lleg‚Ēú‚Ēā a ser un personaje muy popular. En 1947 realiz‚Ēú‚Ēā una gira mundial, visitando Espa‚Ēú‚Ėía en junio. El 21 de ese mes estuvo en Zaragoza. En la foto, acompa‚Ēú‚Ėíada de militares y eclesi‚Ēú√≠sticos (alguien parecido a Nosfetaru asoma a su derecha), reza ante la Virgen del Pilar. Fuente: Archivo Heraldo de Arag‚Ēú‚Ēān.', 1947, 1947, 1947, 'Anos 40', 'CASCO HIST‚Ēú√īRICO', 41.65621500, -0.87731900, '0101000020E6100000001AA54BFF12ECBF841266DAFED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20957798973.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20957798973.webp', 'https://www.flickr.com/photos/zaragozaantigua/20957798973/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25101, 'Corporaci‚Ēú‚Ēān 1991', 'Posado oficial en las escaleras de la Planta Noble del Ayuntamiento de la nueva Corporaci‚Ēú‚Ēān emanada de las elecciones municipales del 26 de mayo de 1991. En el centro y primera fila, Antonio Gonz‚Ēú√≠lez Trivi‚Ēú‚Ėío, que repite como alcalde tras alcanzar el PSOE hasta 15 concejal‚Ēú¬°as (tuvo 13 en 1987). El Partido Popular logr‚Ēú‚Ēā 7 (tuvo 5 en 1987), el Partido Aragon‚Ēú¬ģs Regionalista 6 (tuvo 8 en 1987), y Convergencia Alternativa de Arag‚Ēú‚Ēān-Izquierda Unida 3 (tuvo 2 en 1987). Desapareci‚Ēú‚Ēā de escena el Centro Democr‚Ēú√≠tico y Social, que se present‚Ēú‚Ēā a las elecciones teniendo 3 concejal‚Ēú¬°as.', 1991, 1991, 1991, 'Anos 90', 'CASCO HIST‚Ēú√īRICO', 41.65623200, -0.87732900, '0101000020E6100000E4A25A441413ECBF5A4B0169FFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50379198927.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50379198927.webp', 'https://www.flickr.com/photos/zaragozaantigua/50379198927/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25571, 'Plaza del Pilar 1959', 'A‚Ēú¬ģrea visual panor‚Ēú√≠mica centrada en la nueva y gran plaza del Pilar con el fondo del r‚Ēú¬°o Ebro, la arboleda de Macanaz y el barrio del Arrabal. Los cuatro nuevos espacios que compon‚Ēú¬°an la plaza aparecen definidos, el m‚Ēú√≠s norte‚Ēú‚Ėío, por la Cruz del Altar de la Patria inaugurado finalmente en 1954, y un bosquecillo de cipreses visible en buena parte por el solar donde estaba previsto construir los nuevos juzgados de la ciudad; en el centro, la plaza del Pilar de toda la vida, recayente al hom‚Ēú‚Ēānimo templo, cuyas dos torres ribere‚Ēú‚Ėías siguen en construcci‚Ēú‚Ēān; el tercer espacio, ordenado entre la nueva Casa Consistorial en construcci‚Ēú‚Ēān, y el a‚Ēú‚ēĎn previsto desemboque del prolongado paseo de la Independencia; finalmente y en la parte inferior derecha, el tramo correspondiente a la Lonja En la parte superior y a la izquierda, la Pasarela Peatonal de Macanaz..', 1959, 1959, 1959, 'Anos 50', 'CASCO HIST‚Ēú√īRICO', 41.65640100, -0.87892700, '0101000020E6100000D84812842B20ECBFE607AEF204D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50154232697.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50154232697.webp', 'https://www.flickr.com/photos/zaragozaantigua/50154232697/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
